export function findNearestKRSigungu(lat: number, lon: number): string {
  let nearest = Object.keys(KOREA_SIGUNGU)[0]
  let minDist = Infinity
  for (const [key, r] of Object.entries(KOREA_SIGUNGU)) {
    const d = (lat - r.lat) ** 2 + (lon - r.lon) ** 2
    if (d < minDist) { minDist = d; nearest = key }
  }
  return nearest
}

export function getSigunguDisplayName(key: string): string {
  if (!key.includes('_')) return key
  return key.split('_')[1]
}
